class Solution:
    def maxSelectedElements(self, nums):
        nums.sort()
        # dp[v] = length of best consecutive sequence ending at v
        dp = {}
        for x in nums:
            # option 1: use x as x (keep), extends sequence ending at x-1
            dp[x] = dp.get(x-1, 0) + 1
            # option 2: use x as x+1 (increment), extends sequence ending at x
            # but we need to use the old dp[x] before update for x+1
            dp[x+1] = max(dp.get(x+1, 0), dp.get(x, 0))
        # Recompute properly: process x kept before x+1 incremented for same x
        dp2 = {}
        for x in nums:
            # increment to x+1: chain from dp2[x]
            dp2[x+1] = max(dp2.get(x+1, 0), dp2.get(x, 0) + 1)
            # keep as x: chain from dp2[x-1]
            dp2[x] = max(dp2.get(x, 0), dp2.get(x-1, 0) + 1)
        return max(dp2.values()) if dp2 else 1

