class Solution:
    def maxSelectedElements(self, nums):
        nums.sort()
        dp = {}
        for x in nums:
            # Use x as x+1 first (depends on dp[x] which is sequence ending at x)
            dp[x+1] = dp.get(x, 0) + 1
            # Use x as x (depends on dp[x-1])
            dp[x] = dp.get(x-1, 0) + 1
        return max(dp.values())

