var maxSelectedElements = function(nums) {
    nums.sort((a,b)=>a-b);
    const dp = new Map();
    for (const x of nums) {
        dp.set(x+1, (dp.get(x) || 0) + 1);
        dp.set(x, (dp.get(x-1) || 0) + 1);
    }
    return Math.max(...dp.values());
};
